mapper.select:
SELECT BASE_YM , VIEW_TYPE , MULTI_TYPE , VERSION_CODE , CATEGORY_NAME , APP_NAME , GA_NGA_TYPE , CUSTOMER_NAME , SORT3 , SORT4 , SORT5 , METRIC_TYPE , YEAR_VALUE , QUARTER_VALUE , VALUE_DECIMAL FROM SAMPLE_DYNAMIC_GRID WHERE 1 = 1
AND BASE_YM >= #{startYm}
AND BASE_YM <= #{endYm}
AND VIEW_TYPE = #{radioType}
AND VERSION_CODE = #{singleSelectValue}
AND MULTI_TYPE IN
#{multiType}
AND METRIC_TYPE IN
#{dimension}
ORDER BY CATEGORY_NAME , APP_NAME , GA_NGA_TYPE , CUSTOMER_NAME , METRIC_TYPE , YEAR_VALUE , QUARTER_VALUE

mapper.delete:
DELETE FROM SAMPLE_DYNAMIC_GRID
WHERE 1 = 1
AND VIEW_TYPE = #{radioType}
AND MULTI_TYPE = #{multiType}
AND VERSION_CODE = #{versionCode}
AND CATEGORY_NAME = #{categoryName}
AND APP_NAME = #{appName}
AND GA_NGA_TYPE = #{gaNgaType}
AND CUSTOMER_NAME = #{customerName}

